mapper.select:
SELECT DISTINCT A.line_id,B.line_name,A.stage_id,C.stage_name,A.process_id,D.process_name,A.`status`,A.remark
FROM mes_mac A
LEFT JOIN mes_line B ON B.line_id = A.line_id
LEFT JOIN mes_stage C ON C.stage_id = A.stage_id
LEFT JOIN mes_process D ON D.process_id = A.process_id

    A.del_flag = '0'
     and A.line_id = #{lineId}

     and A.process_id = #{processId}

     and A.stage_id = #{stageId}


where A.mac_name = #{macName}
and A.line_id = #{lineId}
and A.stage_id = #{stageId}
and A.process_id = #{processId}
and del_flag = '0' limit 1

mapper.update:
update mes_mac
line_id = #{lineId}, stage_id = #{stageId}, process_id = #{processId}, mac_name = #{macName}, mac_area = #{macArea}, status = #{status}, remark = #{remark}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime},
where mac_id = #{macId}
